Bahia no Legisla Bahia","cutoff":"2026-05-11","migration_batch_id":"legislacao-p0b-ba-jeronimo-migration-draft-readback-20260511","source_artifact":"fonte interna de curadoria","rescue_artifact":"fonte interna de curadoria","migration_draft_artifact":"fonte interna de curadoria","explicitly_excluded_laws_not_inserted":["15.123/2026","15.121/2026"],"source_disclaimer_preserved":true,"completo_provado_publico_requires":["supabase_apply","readback_service_role_anon","ui_whitelist","cache_revalidate","release_verify"]}'::jsonb);

DO $$
DECLARE
  cand_id uuid;
  seed_count int;
  duplicate_seed_count int;
  excluded_seed_count int;
  lme_total int;
  target_count int;
  projetos_count int;
  mandato_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'jeronimo';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'jeronimo: candidato ausente neste banco local/CI minimo; seed BA Legisla Bahia pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO seed_count FROM _jeronimo_ba_legislabahia_lme_seed;

  IF seed_count <> 238 THEN
    RAISE EXCEPTION 'Pre-condicao jeronimo: seed tem % rows, esperado 238', seed_count;
  END IF;

  SELECT count(*) INTO duplicate_seed_count
  FROM (
    SELECT identificador_fonte
    FROM _jeronimo_ba_legislabahia_lme_seed
    GROUP BY identificador_fonte
    HAVING count(*) > 1
  ) duplicated;

  IF duplicate_seed_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao jeronimo: seed tem % identificadores_fonte duplicados', duplicate_seed_count;
  END IF;

  SELECT count(*) INTO excluded_seed_count
  FROM _jeronimo_ba_legislabahia_lme_seed
  WHERE (numero = '15.123' AND ano = 2026)
     OR (numero = '15.121' AND ano = 2026)
     OR identificador_fonte IN ('BA-LEGISLABAHIA:LEI:15123:2026', 'BA-LEGISLABAHIA:LEI:15121:2026');

  IF excluded_seed_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao jeronimo: seed inclui % leis explicitamente excluidas (15.123/2026 ou 15.121/2026)', excluded_seed_count;
  END IF;

  SELECT count(*) INTO lme_total
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'jeronimo-ba-legislabahia-leis-ordinarias-assinadas-2023-2026-cutoff-20260511';

  IF lme_total NOT IN (0, 238) THEN
    RAISE EXCEPTION 'Pre-condicao jeronimo: LME mudou de 0/238 idempotente para %', lme_total;
  END IF;

  IF lme_total = 238 AND target_count <> 238 THEN
    RAISE EXCEPTION 'Pre-condicao jeronimo: 238 rows LME existentes, mas apenas % com coverage_id alvo', target_count;
  END IF;

  SELECT count(*) INTO projetos_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  IF projetos_count <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao jeronimo: projetos_lei deve permanecer 100, encontrado %', projetos_count;
  END IF;

  SELECT count(*) INTO mandato_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND (hp.cargo ILIKE '%Governador%' OR hp.cargo_canonico = 'Governador')
    AND UPPER(COALESCE(hp.estado, '')) = 'BA'
    AND COALESCE(hp.periodo_inicio, 9999) <= 2023
    AND COALESCE(hp.periodo_fim, 9999) >= 2023;

  IF mandato_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao jeronimo: mandato Governador/BA compativel com 2023 nao encontrado em historico_politico';
  END IF;
END $$;

WITH target AS (
  SELECT
    c.id AS candidato_id,
    seed.*,
    (
      SELECT hp.id
      FROM historico_politico hp
      WHERE hp.candidato_id = c.id
        AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
        AND (hp.cargo ILIKE '%Governador%' OR hp.cargo_canonico = 'Governador')
        AND UPPER(COALESCE(hp.estado, '')) = 'BA'
        AND COALESCE(hp.periodo_inicio, 9999) <= seed.ano
        AND COALESCE(hp.periodo_fim, 9999) >= seed.ano
      ORDER BY
        CASE WHEN hp.periodo_inicio = 2023 THEN 0 ELSE 1 END,
        hp.periodo_inicio DESC NULLS LAST,
        hp.id
      LIMIT 1
    ) AS historico_politico_id
  FROM candidatos c
  CROSS JOIN _jeronimo_ba_legislabahia_lme_seed seed
  WHERE c.slug = 'jeronimo'
)
INSERT INTO legislacao_mandato_executivo (
  candidato_id,
  historico_politico_id,
  tipo_relacao,
  esfera,
  uf_norma,
  tipo_norma,
  numero,
  ano,
  data_norma,
  ementa,
  signatario,
  autoridade_papel,
  fonte_primaria_url,
  fonte_primaria_titulo,
  fonte_tramitacao_url,
  identificador_fonte,
  metadata
)
SELECT
  target.candidato_id,
  target.historico_politico_id,
  target.tipo_relacao,
  target.esfera,
  target.uf_norma,
  target.tipo_norma,
  target.numero,
  target.ano,
  target.data_norma::date,
  target.ementa,
  target.signatario,
  target.autoridade_papel,
  target.fonte_primaria_url,
  target.fonte_primaria_titulo,
  target.fonte_tramitacao_url,
  target.identificador_fonte,
  target.metadata
FROM target
WHERE target.historico_politico_id IS NOT NULL
  AND NOT EXISTS (
    SELECT 1
    FROM legislacao_mandato_executivo lme
    WHERE lme.candidato_id = target.candidato_id
      AND lme.identificador_fonte = target.identificador_fonte
  );

DO $$
DECLARE
  cand_id uuid;
  total_count int;
  scope_count int;
  metadata_count int;
  signatario_count int;
  projetos_count int;
  null_historico_count int;
  excluded_present_count int;
  outside_slug_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'jeronimo';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'jeronimo: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO total_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO scope_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'jeronimo-ba-legislabahia-leis-ordinarias-assinadas-2023-2026-cutoff-20260511'
    AND metadata->>'coverage_scope' = 'inventario_completo_ba_legislabahia_leis_ordinarias_assinadas_jeronimo_2023_2026_cutoff_20260511';

  SELECT count(*) INTO metadata_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'jeronimo-ba-legislabahia-leis-ordinarias-assinadas-2023-2026-cutoff-20260511'
    AND metadata->>'coverage_scope' = 'inventario_completo_ba_legislabahia_leis_ordinarias_assinadas_jeronimo_2023_2026_cutoff_20260511'
    AND metadata->>'coverage_status' = 'completo_escopado_dados'
    AND metadata->>'tabela_alvo' = 'legislacao_mandato_executivo'
    AND metadata->>'projetos_lei_mixed' = 'false'
    AND metadata->>'source_artifact' = 'fonte interna de curadoria'
    AND metadata->>'rescue_artifact' = 'fonte interna de curadoria';

  SELECT count(*) INTO signatario_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'jeronimo-ba-legislabahia-leis-ordinarias-assinadas-2023-2026-cutoff-20260511'
    AND tipo_relacao = 'lei_sancionada'
    AND esfera = 'estadual'
    AND uf_norma = 'BA'
    AND signatario = 'JERÔNIMO RODRIGUES'
    AND autoridade_papel = 'titular';

  SELECT count(*) INTO projetos_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO null_historico_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'jeronimo-ba-legislabahia-leis-ordinarias-assinadas-2023-2026-cutoff-20260511'
    AND historico_politico_id IS NULL;

  SELECT count(*) INTO excluded_present_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND (
      (numero = '15.123' AND ano = 2026)
      OR (numero = '15.121' AND ano = 2026)
      OR identificador_fonte IN ('BA-LEGISLABAHIA:LEI:15123:2026', 'BA-LEGISLABAHIA:LEI:15121:2026')
    );

  SELECT count(*) INTO outside_slug_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id <> cand_id
    AND metadata->>'coverage_id' = 'jeronimo-ba-legislabahia-leis-ordinarias-assinadas-2023-2026-cutoff-20260511';

  IF total_count <> 238 THEN
    RAISE EXCEPTION 'Pos-condicao jeronimo: total LME esperado 238, encontrado %', total_count;
  END IF;

  IF scope_count <> 238 THEN
    RAISE EXCEPTION 'Pos-condicao jeronimo: coverage rows esperadas 238, encontradas %', scope_count;
  END IF;

  IF metadata_count <> 238 THEN
    RAISE EXCEPTION 'Pos-condicao jeronimo: metadata rows esperadas 238, encontradas %', metadata_count;
  END IF;

  IF signatario_count <> 238 THEN
    RAISE EXCEPTION 'Pos-condicao jeronimo: rows assinadas por titular esperadas 238, encontradas %', signatario_count;
  END IF;

  IF projetos_count <> 100 THEN
    RAISE EXCEPTION 'Pos-condicao jeronimo: projetos_lei deve permanecer 100, encontrado %', projetos_count;
  END IF;

  IF null_historico_count <> 0 THEN
    RAISE EXCEPTION 'Pos-condicao jeronimo: % rows alvo sem historico_politico_id', null_historico_count;
  END IF;

  IF excluded_present_count <> 0 THEN
    RAISE EXCEPTION 'Pos-condicao jeronimo: % leis excluidas foram inseridas indevidamente', excluded_present_count;
  END IF;

  IF outside_slug_count <> 0 THEN
    RAISE EXCEPTION 'Pos-condicao jeronimo: % rows de outros slugs com coverage_id alvo', outside_slug_count;
  END IF;

  RAISE NOTICE 'Pos-apply jeronimo BA Legisla Bahia: LME=% coverage_scope=% projetos_lei=% excluded=%', total_count, scope_count, projetos_count, excluded_present_count;
END $$;
